<style>
  .brands-slider{ position:relative; padding:44px 0 0; }
  .brands-slider .swiper-wrapper{ align-items:center; }

  .brands-slider .swiper-slide{
    height:180px;
    display:flex; align-items:center; justify-content:center;
    background:#F1F1F2; border-radius:8px; padding:8px;
  }
  .brands-slider .swiper-slide img{
    max-height:60px; width:auto; height:auto; object-fit:contain;
    filter:grayscale(100%); opacity:.85; transition:.25s ease;
  }
  .brands-slider .swiper-slide img:hover{ filter:none; opacity:1; }

  .brands-slider .swiper-nav{
    position:absolute; top:0; right:0; display:flex; gap:8px; z-index:9;
  }
  .brands-slider .swiper-button-prev,
  .brands-slider .swiper-button-next{
    position:relative; inset:auto;
    width:32px; height:32px; border-radius:8px;
    background:#F1F1F2; color:#32333B;
    display:flex; align-items:center; justify-content:center;
    box-shadow:0 1px 3px rgba(0,0,0,.08); transition:.2s ease;
  }
  .brands-slider .swiper-button-prev:after,
  .brands-slider .swiper-button-next:after{ font-size:14px; }
  .brands-slider .swiper-pagination{ display:none; }

  @media (max-width:767px){
    .brands-slider .swiper-slide{ height:88px; }
    .brands-slider .swiper-slide img{ max-height:46px; }
  }
</style>

<div class="brands-slider">
  <div class="swiper-nav">
    <div class="swiper-button-prev" aria-label="Previous"></div>
    <div class="swiper-button-next" aria-label="Next"></div>
  </div>

  <div class="swiper brands-swiper">
    <div class="swiper-wrapper">
      <div class="swiper-slide"><img src="/wp-content/uploads/2025/08/Mask-group.svg" alt="Philips"></div>
      <div class="swiper-slide"><img src="/wp-content/uploads/2025/08/Group-569.svg" alt="Carestream"></div>
      <div class="swiper-slide"><img src="/wp-content/uploads/2025/08/Group-570.svg" alt="Fujifilm"></div>
      <div class="swiper-slide"><img src="/wp-content/uploads/2025/08/Group-571.svg" alt="Drager"></div>
      <div class="swiper-slide"><img src="/wp-content/uploads/2025/08/Group-572.svg" alt="Konica Minolta"></div>

      <div class="swiper-slide"><img src="/wp-content/uploads/2025/08/image-71.svg" alt="Logo"></div>
      <div class="swiper-slide"><img src="/wp-content/uploads/2025/08/image-70.svg" alt="Logo"></div>
      <div class="swiper-slide"><img src="/wp-content/uploads/2025/08/Mask-group-2.svg" alt="Logo"></div>
      <div class="swiper-slide"><img src="/wp-content/uploads/2025/08/Mask-group-1.svg" alt="Logo"></div>
      <div class="swiper-slide"><img src="/wp-content/uploads/2025/08/image-69.svg" alt="Logo"></div>
      <div class="swiper-slide"><img src="/wp-content/uploads/2025/08/image-68.svg" alt="Logo"></div>
      <div class="swiper-slide"><img src="/wp-content/uploads/2025/08/image-67-1.svg" alt="Logo"></div>
      <div class="swiper-slide"><img src="/wp-content/uploads/2025/08/image-67.svg" alt="Logo"></div>
      <div class="swiper-slide"><img src="/wp-content/uploads/2025/08/image-65.svg" alt="Logo"></div>
      <div class="swiper-slide"><img src="/wp-content/uploads/2025/08/image.svg" alt="Logo"></div>
    </div>
  </div>
</div>

<script src="https://unpkg.com/swiper@9/swiper-bundle.min.js"></script>
<script>
  (function () {
    const slider = new Swiper('.brands-swiper', {
      speed: 600,
      autoplay: { delay: 2500, disableOnInteraction: false },
      slidesPerView: 5,
      spaceBetween: 8,

      loop: false,       // убираем loop
      rewind: true,      // доходим до конца и «перематываем» в начало
      slidesPerGroup: 1, // шаг по одному лого

      navigation: {
        nextEl: '.brands-slider .swiper-button-next',
        prevEl: '.brands-slider .swiper-button-prev',
      },

      breakpoints: {
        320:  { slidesPerView: 2, spaceBetween: 8 },
        480:  { slidesPerView: 3, spaceBetween: 8 },
        768:  { slidesPerView: 4, spaceBetween: 8 },
        1024: { slidesPerView: 5, spaceBetween: 8 }
      }
    });

    const root = document.querySelector('.brands-slider');
    root.addEventListener('mouseenter', () => slider.autoplay.stop());
    root.addEventListener('mouseleave', () => slider.autoplay.start());
  })();
</script>
"},"elements":[],"widgetType":"html"}],"isInner":true}],"isInner":false}]

