ps://unpkg.com/swiper@9/swiper-bundle.min.css"/>

<style>
  .brands-slider{ position:relative; padding:44px 0 0; }
  .brands-slider .swiper-wrapper{ align-items:center; }

  .brands-slider .swiper-slide{
    height:180px;
    display:flex; align-items:center; justify-content:center;
    background:#F1F1F2; border-radius:8px; padding:8px;
  }
  
  .brands-slider .swiper-slide a{
    display:flex; align-items:center; justify-content:center;
    width:100%; height:100%;
  }

  .brands-slider .swiper-slide img{
    max-height:46px; width:auto; height:auto; object-fit:contain;
    filter:grayscale(100%); opacity:.85; transition:.25s ease;
  }
  .brands-slider .swiper-slide img:hover{ filter:none; opacity:1; }

  .brands-slider .swiper-nav{
    position:absolute; top:0; right:0; display:flex; gap:8px; z-index:9;
  }
  .brands-slider .swiper-button-prev,
  .brands-slider .swiper-button-next{
    position:relative; inset:auto;
    width:32px; height:32px; border-radius:8px;
    background:#F1F1F2; color:#32333B;
    display:flex; align-items:center; justify-content:center;
    box-shadow:0 1px 3px rgba(0,0,0,.08); transition:.2s ease;
  }
  .brands-slider .swiper-button-prev:after,
  .brands-slider .swiper-button-next:after{ font-size:14px; }
  .brands-slider .swiper-pagination{ display:none; }
    .brands-slider .swiper-slide img[src*="Konica_Minolta"],
  .brands-slider .swiper-slide img[src*="General_Electric_logo"],
  .brands-slider .swiper-slide img[src*="BioMerieux_logo"],
  .brands-slider .swiper-slide img[src*="Roche_Logo"]{
    max-height:72px;
  }

  @media (max-width:767px){
  .brands-slider .swiper-slide{ height: 200px; }     
  .brands-slider .swiper-slide img{
    max-height: 46px;                                
    filter: none !important;                         
    opacity: 1 !important;                           
  }
  .brands-slider .swiper-slide img:hover{
    -webkit-filter: none !important;                 
    filter: none !important;
    opacity: 1 !important;
  }
  .brands-slider .swiper-slide img[src*="Konica_Minolta"],
    .brands-slider .swiper-slide img[src*="General_Electric_logo"],
    .brands-slider .swiper-slide img[src*="BioMerieux_logo"],
    .brands-slider .swiper-slide img[src*="Roche_Logo"]{
      max-height:72px;
    
}
</style>

<div class="brands-slider">
  <div class="swiper-nav">
    <div class="swiper-button-prev" aria-label="Previous"></div>
    <div class="swiper-button-next" aria-label="Next"></div>
  </div>

  <div class="swiper brands-swiper">
    <div class="swiper-wrapper">
      <div class="swiper-slide">
        <a href="https://www.global.toshiba/" target="_blank" rel="noopener noreferrer" aria-label="Toshiba">
