<script src="https://unpkg.com/swiper@9/swiper-bundle.min.js"></script>
<script>
  (function () {
    const slider = new Swiper('.brands-swiper', {
      speed: 600,
      autoplay: { delay: 2500, disableOnInteraction: false },
      slidesPerView: 5,
      spaceBetween: 8,

      loop: false,       
      rewind: true,      
      slidesPerGroup: 1, 

      navigation: {
        nextEl: '.brands-slider .swiper-button-next',
        prevEl: '.brands-slider .swiper-button-prev',
      },

      breakpoints: {
        320:  { slidesPerView: 1, spaceBetween: 8 },
        480:  { slidesPerView: 1, spaceBetween: 8 },
        768:  { slidesPerView: 2, spaceBetween: 8 },
        1024: { slidesPerView: 5, spaceBetween: 8 }
      }
    });

    const root = document.querySelector('.brands-slider');
    root.addEventListener('mouseenter', () => slider.autoplay.stop());
    root.addEventListener('mouseleave', () => slider.autoplay.start());
  })();
</script>


