        </a>
      </div>

      <div class="swiper-slide">
        <a href="https://www.konicaminolta.com/" target="_blank" rel="noopener noreferrer" aria-label="Konica Minolta">
          <img src="/wp-content/uploads/2025/10/Konica_Minolta-Logo.svg" alt="Konica Minolta">
