      </div>

      <div class="swiper-slide">
        <a href="https://www.fujifilm.com/" target="_blank" rel="noopener noreferrer" aria-label="Fujifilm">
          <img src="/wp-content/uploads/2025/10/Fujifilm_logo.svg" alt="Fujifilm">
        </a>
      </div>

      <div class="swiper-slide">
        <a href="https://www.freseniusmedicalcare.com/" target="_blank" rel="noopener noreferrer" aria-label="Fresenius Medical Care">
          <img src="/wp-content/uploads/2025/10/Fresenius_Medical_Care_logo.svg" alt="Fresenius Medical Care">
        </a>
      </div>

      <div class="swiper-slide">
        <a href="https://www.draeger.com/" target="_blank" rel="noopener noreferrer" aria-label="Dräger">
          <img src="/wp-content/uploads/2025/10/Drager_Logo.svg" alt="Dräger">
        </a>
      </div>

      <div class="swiper-slide">
        <a href="https://www.carestream.com/" target="_blank" rel="noopener noreferrer" aria-label="Carestream">
          <img src="/wp-content/uploads/2025/10/Carestream_Logo.svg" alt="Carestream">
        </a>
      </div>

      <div class="swiper-slide">
        <a href="https://www.biomerieux.com/" target="_blank" rel="noopener noreferrer" aria-label="bioMérieux">
          <img src="/wp-content/uploads/2025/10/BioMerieux_logo.svg" alt="bioMérieux">
        </a>
      </div>

      <div class="swiper-slide">
        <a href="https://www.bd.com/" target="_blank" rel="noopener noreferrer" aria-label="BD (Becton, Dickinson)">
          <img src="/wp-content/uploads/2025/10/Becton_Dickinson_logo.svg" alt="BD (Becton, Dickinson)">
        </a>
      </div>

      <div class="swiper-slide">
        <a href="https://www.beckmancoulter.com/" target="_blank" rel="noopener noreferrer" aria-label="Beckman Coulter">
          <img src="/wp-content/uploads/2025/10/Beckman_Coulter_Logo.svg" alt="Beckman Coulter">
        </a>
      </div>
    </div>
  </div>
</div>

<script src="https://unpkg.com/swiper@9/swiper-bundle.min.js"></script>
<script>
  (function () {
    const slider = new Swiper('.brands-swiper', {
      speed: 600,
      autoplay: { delay: 2500, disableOnInteraction: false },
      slidesPerView: 5,
      spaceBetween: 8,

      loop: false,       
      rewind: true,      
      slidesPerGroup: 1, 

      navigation: {
        nextEl: '.brands-slider .swiper-button-next',
        prevEl: '.brands-slider .swiper-button-prev',
      },

      breakpoints: {
        320:  { slidesPerView: 1, spaceBetween: 8 },
        480:  { slidesPerView: 1, spaceBetween: 8 },
        768:  { slidesPerView: 2, spaceBetween: 8 },
        1024: { slidesPerView: 5, spaceBetween: 8 }
      }
    });

    const root = document.querySelector('.brands-slider');
    root.addEventListener('mouseenter', () => slider.autoplay.stop());
    root.addEventListener('mouseleave', () => slider.autoplay.start());
  })();
</script>


